from prometheus_client import Counter, generate_latest, REGISTRY
from flask import Flask, request, Response
import time

app = Flask(__name__)

# Dictionary to store dynamically created metrics for each user-path combination
user_path_metrics = {}

def get_or_create_metric(user_id, path):
    """Get existing metric or create new one for user-path combination"""
    metric_key = f"user_{user_id}_path_{path.replace('/', '_').replace('-', '_').replace('.', '_')}"
    
    # Sanitize metric key to be valid Prometheus metric name
    metric_key = ''.join(c if c.isalnum() or c == '_' else '_' for c in metric_key)
    metric_key = metric_key.strip('_')
    
    if metric_key not in user_path_metrics:
        # Create new counter for this specific user-path combination
        metric_name = f"http_requests_{metric_key}"
        user_path_metrics[metric_key] = Counter(
            metric_name,
            f'HTTP requests for user {user_id} on path {path}',
            ['user_id', 'session_id', 'path', 'method', 'status']
        )
    
    return user_path_metrics[metric_key]

@app.before_request
def track_request():
    """Track request start time"""
    request.start_time = time.time()

@app.after_request
def record_metrics(response):
    """Record metrics after each request"""
    # Extract user_id and session_id from headers or query params
    user_id = request.headers.get('X-User-ID', request.args.get('user_id', 'anonymous'))
    session_id = request.headers.get('X-Session-ID', request.args.get('session_id', 'no_session'))
    path = request.path
    method = request.method
    status = str(response.status_code)
    
    # Get or create metric for this user-path combination
    metric = get_or_create_metric(user_id, path)
    
    # Increment the counter with labels
    metric.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method,
        status=status
    ).inc()
    
    return response

@app.route('/metrics')
def metrics():
    """Expose Prometheus metrics"""
    return Response(generate_latest(REGISTRY), mimetype='text/plain')

@app.route('/')
def home():
    return {'message': 'Hello, World!', 'endpoint': '/'}

@app.route('/api/users')
def users():
    return {'users': ['user1', 'user2', 'user3'], 'endpoint': '/api/users'}

@app.route('/api/products')
def products():
    return {'products': ['product1', 'product2'], 'endpoint': '/api/products'}

@app.route('/api/orders')
def orders():
    return {'orders': ['order1', 'order2'], 'endpoint': '/api/orders'}

@app.route('/api/user/<user_id>')
def user_detail(user_id):
    return {'user_id': user_id, 'endpoint': f'/api/user/{user_id}'}

@app.route('/api/product/<product_id>')
def product_detail(product_id):
    return {'product_id': product_id, 'endpoint': f'/api/product/{product_id}'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)